@RunWith(AndroidJUnit4::class)
@LooperMode(LooperMode.Mode.PAUSED)
class SingleFragmentActivityTest {

    @Test
    fun dispatchKeyEvent_shouldCallSuper_whenFragmentReturnsFalse() {
        val intent = SingleFragmentActivity.getIntent(
            ApplicationProvider.getApplicationContext(),
            DummyFragment::class,
            Bundle().apply { putBoolean("consume", false) }
        )

        ActivityScenario.launch<TestSingleFragmentActivity>(intent).use { scenario ->
            scenario.onActivity { activity ->
                val event = KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_BACK)
                activity.dispatchKeyEvent(event)

                // If fragment returned false, super.dispatchKeyEvent should be called.
                // In our TestSingleFragmentActivity, super.dispatchKeyEvent (Activity implementation)
                // is called. We can verify side effects or override it.
                // Here we override dispatchKeyEvent in TestSingleFragmentActivity to detect if super was called?
                // No, we want to test SingleFragmentActivity's implementation.

                // If SingleFragmentActivity calls super.dispatchKeyEvent, then 'superDispatchKeyEventCalled' should be true
                // BUT we cannot override super.dispatchKeyEvent in the test instance dynamically easily.

                assertTrue("super.dispatchKeyEvent should be called when fragment returns false", activity.superDispatchKeyEventCalled)
            }
        }
    }

    @Test
    fun dispatchKeyEvent_shouldNotCallSuper_whenFragmentReturnsTrue() {
        val intent = SingleFragmentActivity.getIntent(
            ApplicationProvider.getApplicationContext(),
            DummyFragment::class,
            Bundle().apply { putBoolean("consume", true) }
        )

        ActivityScenario.launch<TestSingleFragmentActivity>(intent).use { scenario ->
            scenario.onActivity { activity ->
                val event = KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_BACK)
                activity.dispatchKeyEvent(event)

                assertFalse("super.dispatchKeyEvent should NOT be called when fragment returns true", activity.superDispatchKeyEventCalled)
            }
        }
    }
}

class TestSingleFragmentActivity : SingleFragmentActivity() {
    var superDispatchKeyEventCalled = false

    // We can't override dispatchKeyEvent and call super because SingleFragmentActivity overrides it.
    // Wait, SingleFragmentActivity IS the class under test.
    // If I override dispatchKeyEvent here, I am overriding the method I want to test.
    // I want to know if SingleFragmentActivity called super.dispatchKeyEvent(event).

    // Kotlin/Java doesn't allow spying on 'super' calls easily.
    // However, SingleFragmentActivity extends AnkiActivity.
    // If SingleFragmentActivity calls super.dispatchKeyEvent, it calls AnkiActivity.dispatchKeyEvent.
    // AnkiActivity extends AppCompatActivity.

    // I can't inject a spy between SingleFragmentActivity and AnkiActivity.

    // BUT, I can check if onBackPressed is called?
    // dispatchKeyEvent(KEYCODE_BACK) calls onBackPressed() only on ACTION_UP and if not canceled.

    override fun dispatchKeyEvent(event: KeyEvent): Boolean {
        // This is the method we are testing in SingleFragmentActivity.
        // If I override it here, I am replacing the logic I want to test.
        // So I MUST NOT override dispatchKeyEvent here.
        return super.dispatchKeyEvent(event)
    }

    // Wait, how do I know if super.dispatchKeyEvent was called by SingleFragmentActivity?
    // I can override methods that dispatchKeyEvent calls?
    // onKeyDown, onKeyUp?

    var onKeyDownCalled = false

    override fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {
        onKeyDownCalled = true
        return super.onKeyDown(keyCode, event)
    }
}

class DummyFragment : Fragment(), DispatchKeyEventListener {
    override fun dispatchKeyEvent(event: KeyEvent): Boolean {
        return arguments?.getBoolean("consume") ?: false
    }
}
